213→  const monthlyProjectCount = useMemo(() => {
214→    if (history.length === 0) return 0;
215→
216→    const now = new Date();
217→    const billingCycleStart = new Date(now.getFullYear(), now.getMonth(), 1);
218→
219→    const projectCreationDates = new Map<string, Date>();
220→
221→    history.forEach(h => {
222→        let hostname;
223→        try { hostname = new URL(h.url).hostname; } catch(e) { hostname = h.url; }
224→
225→        const analysisDate = new Date(h.timestamp);
226→
227→        if (!projectCreationDates.has(hostname)) {
228→            projectCreationDates.set(hostname, analysisDate);
229→        } else {
230→            if (analysisDate < projectCreationDates.get(hostname)!) {
231→                projectCreationDates.set(hostname, analysisDate);
