302→        try { hostname = new URL(url).hostname; } catch(e) {}
303→
304→        const isExistingProject = history.some(h => {
305→            try { return new URL(h.url).hostname === hostname; }
306→            catch(e) { return false; }
307→        });
308→
309→        if (!isExistingProject && monthlyProjectCount >= limit) {
