339→            db.update(0, updated);
340→            return [updated, ...prev.slice(1)];
341→          });
342→          setAnalysisData(prev => prev ? { ...prev, preGenerated } : prev);
343→          setMegaStatus('completed');
344→        } else {
345→          setMegaStatus('failed');
346→        }
347→      }).catch(() => setMegaStatus('failed'));
