376→    const timestamp = new Date().toISOString();
377→    const solutionWithMeta = { ...solution, timestamp };
378→
379→    setAnalysisData(prev => {
380→        if (!prev || prev.timestamp !== analysisId) return prev;
381→        return {
382→            ...prev,
383→            generatedSolutions: {
384→                ...(prev.generatedSolutions || {}),
385→                [recommendationId]: solutionWithMeta
386→            }
387→        };
388→    });
389→
390→    setHistory(prevHistory => {
391→        const index = prevHistory.findIndex(item => item.timestamp === analysisId);
392→        if (index !== -1) {
393→            const updatedItem = {
394→                ...prevHistory[index],
395→                generatedSolutions: {
396→                    ...(prevHistory[index].generatedSolutions || {}),
397→                    [recommendationId]: solutionWithMeta
398→                }
399→            };
