  1→import { z } from 'zod';
  2→
  3→export const waitlistSchema = z.object({
  4→  email: z.string().email('Please enter a valid email address'),
  5→  name: z.string().min(1, 'Name is required').max(100),
  6→  company: z.string().max(200).optional(),
  7→  source: z.enum(['direct', 'producthunt', 'twitter', 'linkedin', 'hackernews', 'reddit']).default('direct'),
  8→});
  9→
 10→export type WaitlistFormData = z.infer<typeof waitlistSchema>;
 11→
 12→export interface WaitlistResponse {
 13→  success: boolean;
 14→  signupNumber?: number;
 15→  foundingTier?: 'top100' | 'top500' | null;
 16→  error?: string;
 17→}
 18→
 19→const WAITLIST_STORAGE_KEY = 'citedby_waitlist';
 20→
 21→function getLocalWaitlist(): WaitlistFormData[] {
 22→  try {
 23→    return JSON.parse(localStorage.getItem(WAITLIST_STORAGE_KEY) || '[]');
 24→  } catch {
 25→    return [];
 26→  }
 27→}
 28→
 29→export async function joinWaitlist(data: WaitlistFormData): Promise<WaitlistResponse> {
 30→  const parsed = waitlistSchema.safeParse(data);
 31→  if (!parsed.success) {
 32→    return { success: false, error: parsed.error.errors[0].message };
 33→  }
 34→
 35→  const supabaseUrl = import.meta.env.VITE_SUPABASE_URL;
 36→  const supabaseKey = import.meta.env.VITE_SUPABASE_ANON_KEY;
 37→
 38→  if (supabaseUrl && supabaseKey) {
 39→    try {
 40→      const response = await fetch(`${supabaseUrl}/rest/v1/waitlist_subscribers`, {
 41→        method: 'POST',
 42→        headers: {
 43→          'Content-Type': 'application/json',
 44→          'apikey': supabaseKey,
 45→          'Authorization': `Bearer ${supabaseKey}`,
 46→          'Prefer': 'return=representation',
 47→        },
 48→        body: JSON.stringify({
 49→          email: parsed.data.email,
 50→          name: parsed.data.name,
 51→          company: parsed.data.company || null,
 52→          source: parsed.data.source,
 53→        }),
 54→      });
 55→
 56→      if (response.status === 409) {
 57→        return { success: false, error: 'This email is already on the waitlist!' };
 58→      }
 59→
 60→      if (!response.ok) {
 61→        throw new Error(`Supabase error: ${response.status}`);
 62→      }
 63→
 64→      const [result] = await response.json();
 65→      return {
 66→        success: true,
 67→        signupNumber: result.signup_number,
 68→        foundingTier: result.founding_tier,
 69→      };
 70→    } catch (err) {
 71→      console.warn('Supabase waitlist failed, using localStorage fallback:', err);
 72→    }
 73→  }
 74→
 75→  const list = getLocalWaitlist();
 76→  if (list.some(e => e.email === parsed.data.email)) {
 77→    return { success: false, error: 'This email is already on the waitlist!' };
 78→  }
 79→  list.push(parsed.data);
 80→  localStorage.setItem(WAITLIST_STORAGE_KEY, JSON.stringify(list));
 81→  const number = list.length;
 82→  return {
 83→    success: true,
 84→    signupNumber: number,
 85→    foundingTier: number <= 100 ? 'top100' : number <= 500 ? 'top500' : null,
 86→  };
 87→}
