 89→export async function getWaitlistCount(): Promise<number> {
 90→  const supabaseUrl = import.meta.env.VITE_SUPABASE_URL;
 91→  const supabaseKey = import.meta.env.VITE_SUPABASE_ANON_KEY;
 92→
 93→  if (supabaseUrl && supabaseKey) {
 94→    try {
 95→      const response = await fetch(`${supabaseUrl}/rest/v1/rpc/get_waitlist_count`, {
 96→        method: 'POST',
 97→        headers: {
 98→          'Content-Type': 'application/json',
 99→          'apikey': supabaseKey,
100→          'Authorization': `Bearer ${supabaseKey}`,
101→        },
102→      });
103→      if (response.ok) {
104→        return await response.json();
105→      }
106→    } catch {
107→      // fall through to localStorage
108→    }
109→  }
110→
111→  return getLocalWaitlist().length;
112→}
